static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 128;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Ca6k04593CustomTilingData tiling;
    const gert::Shape &shape = context->GetInputShape(0)->GetOriginShape();
    uint32_t batch = shape.GetDim(0);
    uint32_t channels = shape.GetDim(1);
    uint32_t depth = shape.GetDim(2);
    uint32_t height = shape.GetDim(3);
    uint32_t width = shape.GetDim(4);
    uint32_t spatial = depth * height * width;
    uint32_t totalLength = batch * channels * spatial;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    float eps = attrs->GetAttrPointer<float>(0)[0];

    uint32_t maxTile = UB_BUDGET_BYTES / (5 * sizeof(float));
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > 32768) maxTile = 32768;

    uint32_t tileLen = spatial;
    if (tileLen > maxTile) tileLen = AlignDown(maxTile, ALIGN_ELEMS);
    if (tileLen == 0) tileLen = maxTile;

    uint32_t numRows = batch * channels;
    uint32_t blockDim = numRows;
    if (blockDim < 8) blockDim = 8;
